var e=JSON.parse(`[{"id":"L5_1","type":"dialog","speaker":"MERCENARY_VOICE_NULL_A","text":{"KOREA":"빌어먹을......! 이 자식 카운터였어!","JPN":"くそっ……！　こいつ、カウンターだった！","ENG":"Darn it! This guy's a Counter!","TWN":"真該死……！這傢伙竟然是制裁者！"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MERCENARY_VOICE_NULL_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MERCENARY_VOICE_NULL_B","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"MERCENARY_VOICE_NULL_B","text":{"KOREA":"어디서 고용한 녀석이냐! 어서 불어!","JPN":"どこに雇われたんだ！　早く言え！","ENG":"Who paid you? You'd better fess up!","TWN":"你是誰雇的傢伙！快點說啊！"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MERCENARY_VOICE_NULL_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MERCENARY_VOICE_NULL_B","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"MERCENARY_VOICE_NULL_B","text":{"KOREA":"크억......!","JPN":"ガハッ……！","ENG":"Ack!","TWN":"唔呃……！"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MERCENARY_VOICE_NULL_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MERCENARY_VOICE_NULL_B","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"카운터면 죄다 돈 받아먹고 심부름 하러 다니는 줄 아냐?","JPN":"カウンターならみんな、金さえもらえば使い走りになるとでも思ってんのか？","ENG":"You reckon all Counters are just a bunch of errand boys and girls?","TWN":"你以為制裁者是拿錢只當跑腿的而已嗎？"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"어디서 온 놈들인지 불기나 해. 여기가 누구 구역인지 알긴 하냐?","JPN":"どこから来たのか言え。ここが誰の縄張りかわかってるのか？","ENG":"Why don't you tell me where you're from? Are you even aware whose territory this is?","TWN":"你到底是從哪裡來的，趕快說啊，你知道這裡是誰的地盤嗎？"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"MERCENARY_VOICE_NULL_C","text":{"KOREA":"흥. 네놈 때문에 우리 카지노가 간판 내리게 생겼어. 접수하느라 꽤 공들인 곳인데 말이야.","JPN":"ふん。お前のせいで、うちのカジノが潰れそうなんだ。手に入れるのに苦労したのによ。","ENG":"Hmpf! Our casino's about to close down because of you. It took us a lot of effort to claim this place.","TWN":"哼，因為你這傢伙，我們的賭場都快要關店了，為了接手我費了不少功夫呢。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERCENARY_VOICE_NULL_C","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL"},{"id":"L14_1","type":"dialog","speaker":"MERCENARY_VOICE_NULL_C","text":{"KOREA":"누가 시켰는지 순순히 불어. 그럼 적어도 고통 없이 끝내주지.","JPN":"誰の指示か早く言え。そうすれば、すぐ楽にしてやる。","ENG":"Tell us who got you to do this. Then we'll make it short and painless when we kill you.","TWN":"到底誰主使的，你最好老實招供，至少我會讓你不感到痛苦地死去。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERCENARY_VOICE_NULL_C","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"와아...... 손님 등쳐 먹는 놈들이 협박도 하네?","JPN":"うわ……客を騙したうえに脅迫まですんのか。","ENG":"Blimey... You lying cheats have the nerve to threaten me?","TWN":"哇啊……欺騙客人的傢伙還感威脅別人啊？"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"딜러란 녀석이 손기술을 그렇게 대놓고 치는데 입이 안 근질거리겠냐?","JPN":"ディーラーがあんなに堂々とイカサマしたんだ。仕方ないだろ？","ENG":"I had to tell him off! That dealer was obviously trying to cheat!","TWN":"發牌的傢伙竟敢明目張膽地出老千，怎麼可能閉上嘴巴不講呢？"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"MERCENARY_VOICE_NULL_C","text":{"KOREA":"쳇......!","JPN":"チッ……！","ENG":"Hmpf!","TWN":"切……！"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERCENARY_VOICE_NULL_C","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"꼬우면 어디 한 번 덤벼 보시던가. 우리 집안 신조가 <color=#ffd34c>오는 놈 안 막는다</color> 야.","JPN":"気に入らないなら、かかってこい。\\nうちのモットーは<color=#ffd34c>来るもの拒まず</color>だ。","ENG":"You're welcome to try me if you dare. After all, my family motto is, \\"<color=#ffd34c>If they're asking for it, give it to them</color>.\\"","TWN":"不高興的話就上來啊，我家的信條是 <color=#ffd34c>來者不拒</color>呢。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"MERCENARY_VOICE_NULL_C","text":{"KOREA":"......흥. 그래. 기억 났다.","JPN":"……ふん。ああそうだ、思い出した。","ENG":"Hmpf. I see. Now I remember.","TWN":"……哼，很好，我想起來了。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERCENARY_VOICE_NULL_C","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"MERCENARY_VOICE_NULL_C","text":{"KOREA":"이 지역 놈들이 그러더군. 촌스러운 보라색 정장 입은 녀석과 엮이면 피곤해질 거라고.","JPN":"この辺のやつらが言ってたな。\\nダサい紫のスーツを着たやつと絡むと厄介なことになるって。","ENG":"I heard the local guys say something like this. Getting involved with a guy in a tacky purple suit will be a headache.","TWN":"這地區的傢伙曾經告訴我，說是有一個穿著土裡土氣紫色西裝的傢伙，若是被他纏上會很麻煩的。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERCENARY_VOICE_NULL_C","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"핫, 그딴 소릴 누가 해? 내 앞에 데리고 와 보지 그래?","JPN":"は？　誰がそんなこと言ったんだ？　俺の前に連れて来い。","ENG":"Ha! Who's been telling you such nonsense? What don't you bring them to me?","TWN":"哈，那是誰說的？把他帶來給我看看？"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"MERCENARY_VOICE_NULL_C","text":{"KOREA":"그건 안 되겠는걸. 지금쯤 바다 밑바닥에서 물고기들이랑 노느라 바쁠 테니까.","JPN":"それは無理だな。今頃、海の底で魚のエサになってるだろうからな。","ENG":"I'm afraid that won't be possible. They're probably too busy playing with the fishes at the bottom of the sea right now.","TWN":"這恐怕不行。因為他現在應該已經在海中大魚的肚子裡了。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERCENARY_VOICE_NULL_C","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"이런...... 막 나가는 녀석들이셨구만.","JPN":"はあ……かなりヤバいやつらだな。","ENG":"Oh my... So you blokes like to play rough, don't you?","TWN":"該死的……原來是一群瘋子。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"MERCENARY_VOICE_NULL_C","text":{"KOREA":"얼치기들 좀 상대해 봤다고 기고만장해하는데, 사람 잘못 봤어. 꼬마야.","JPN":"チンピラ相手にイキってたようだが、今回は相手が悪かったようだな。チビ。","ENG":"Maybe you had better luck with a few punks, but you picked the wrong people to mess with this time. Kid.","TWN":"不過是打贏了一些半吊子就這麼囂張，這次可不一樣喔，小朋友。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERCENARY_VOICE_NULL_C","face":"UNIT_IDLE"},"R":{"char_id":"MERCENARY_VOICE_NULL_A","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"MERCENARY_VOICE_NULL_C","text":{"KOREA":"죽여 버려!","JPN":"やっちまえ！","ENG":"Kill him!","TWN":"去死吧！"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERCENARY_VOICE_NULL_C","face":"UNIT_IDLE"},"R":{"char_id":"MERCENARY_VOICE_NULL_A","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"하아...... 하......","JPN":"はあ……はあ……","ENG":"*Huff... huff...*","TWN":"哈啊……哈……"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"잘못 보긴 뭘 잘못 봐. 깡패 놈아. 쥐어 터지는 건 똑같구만.","JPN":"相手が悪い？　バカ言うな。その言葉、そのまま返してやるよ。","ENG":"You're the one who picked the wrong bloke. Stupid punks. You're no different from the rest of them.","TWN":"不一樣你個大頭鬼，臭流氓。還不是一樣被我捏爛了。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"MERCENARY_VOICE_NULL_C","text":{"KOREA":"하하! 멍청한 놈! 뒤통수가 텅 비었어!","JPN":"はは！　バカなやつだ！　背中が無防備すぎる！","ENG":"Hah hah! Fool! Your backside is wide open!","TWN":"哈哈！愚蠢的傢伙！真是沒腦子！"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERCENARY_VOICE_NULL_C","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"쳇, 숨어 있었나?!","JPN":"チッ、隠れてやがったのか！","ENG":"Tsk, have you been hiding?","TWN":"切，躲起來了？！"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"MERCENARY_VOICE_NULL_C","text":{"KOREA":"이, 이런 썩을......!","JPN":"く、くそ……！","ENG":"D-dammit!","TWN":"你、你這該死的……！"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERCENARY_VOICE_NULL_C","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"하핫. 요새 길거리 싸움은 꽤 거칠군. 한숨 푹 쉬게.","JPN":"はは、最近のケンカは荒っぽいな。ゆっくり休むといい。","ENG":"Hah hah. There's no sense of honor in street brawls nowadays, is there. Sweet dreams.","TWN":"哈哈，最近街頭鬥毆相當兇殘啊。你休息一下吧。"},"stage":{"bg":"BACKSTREET","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"다친 데는 없나, 젊은이?","JPN":"君、ケガはないか？","ENG":"Are you alright, young man?","TWN":"你沒受傷吧，年輕人？"},"stage":{"bg":"BACKSTREET","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"뭐, 뭐야? 당신 지금 내 그림자에서 튀어 나온 거야?","JPN":"な、何だ？　お前、俺の影から飛び出たよな？","ENG":"W-what the hell? Did you just pop out of my shadow?","TWN":"什、什麼鬼？你是從我的影子裡跳出來的嗎？"},"stage":{"bg":"BACKSTREET","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L48_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"별거 아닌 잔재주라네. 너무 놀라지 말게.","JPN":"ちょっとした裏技だ。そんなに驚くな。","ENG":"Just a little parlour trick. Nothing to be alarmed about.","TWN":"雕蟲小技，不用太驚訝。"},"stage":{"bg":"BACKSTREET","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L49_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"굳이 참견할 생각은 아니었네만, 자네가 꽤 위험해 보여서 말이야.","JPN":"手を出すつもりはなかったが、間一髪というところだったものでな。","ENG":"I did not mean to intrude, but it seemed you were in a bit of a tight spot.","TWN":"我本來不想插手的，但看到你太危險了，就沒有忍住。"},"stage":{"bg":"BACKSTREET","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L1_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"이건...... 저격총이잖아?","JPN":"これは……狙撃銃？","ENG":"Isn't this... a sniper rifle?","TWN":"這個……不是狙擊槍嗎？"},"stage":{"bg":"BACKSTREET","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"옥상 위에서 자넬 노리던 녀석들에게서 받아 왔지.","JPN":"屋上で君を狙っていたヤツから頂いて来たんだ。","ENG":"Courtesy of the gentlemen who were taking aim at you from the rooftop.","TWN":"我是從屋頂上瞄準你的那些傢伙手上拿的。"},"stage":{"bg":"BACKSTREET","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"제대로 된 싸움꾼에겐 가까운 곳뿐만 아니라 멀리 보는 시야도 필요한 법이라네.","JPN":"喧嘩屋には近い所だけではなく、遠い所も見渡す視野の広さが必要だ。","ENG":"A capable fighter knows how to keep his field of vision wide enough to detect distant threats, as well as those in close proximity.","TWN":"一個好的戰士，需要同時觀察近處和遠處的情況。"},"stage":{"bg":"BACKSTREET","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"나 원, 귀찮은 녀석들이랑 엮여 버렸네......","JPN":"はあ、面倒なヤツらと絡んじまったぜ……","ENG":"Blimey... Sounds like these blokes and their friends are going to be a nuisance...","TWN":"真是的，被一群煩人的傢伙纏上了……"},"stage":{"bg":"BACKSTREET","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L5_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"하하, 앞으로도 그런 식으로 싸운다면 귀찮은 정도로 끝나진 않을 걸세.","JPN":"はは。この先もそんな戦い方を続ければ、面倒どころじゃ済まないだろう。","ENG":"Hah hah, they'll be more than a nuisance if you keep fighting in that manner.","TWN":"哈哈，以後你還用那種方式打架的話，可就不只是麻煩了。"},"stage":{"bg":"BACKSTREET","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L6_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"그런 식? 내가 싸우는 게 뭐 어때서?","JPN":"そんな戦い方？　俺のやり方に、何か文句でもあるのか？","ENG":"What manner? What's wrong with the way I fight?","TWN":"那種方式？我的方式怎麼了？"},"stage":{"bg":"BACKSTREET","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"카운터면서도 보통 사람들처럼 주먹질이나 하고 있지 않나?","JPN":"カウンターのくせに、凡人みたいな殴り合いをしているだろ？","ENG":"You are a Counter, yet you brawl with your fists like an ordinary person.","TWN":"你身為制裁者，但卻像普通人一樣和別人互毆不是嗎？"},"stage":{"bg":"BACKSTREET","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"날아다니는 법을 배우지 못해서 땅을 걸어 다니는 참새 같은 꼴이지.","JPN":"飛び方を学べなかったせいで、地面を歩いてるスズメと一緒だ。","ENG":"Rather like a sparrow who hops about on the ground because he never learned how to fly.","TWN":"就好像一隻沒學會飛，只能在地上蹦蹦跳的麻雀。"},"stage":{"bg":"BACKSTREET","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"하아......","JPN":"はあ……","ENG":"*Sigh*","TWN":"哈啊……"},"stage":{"bg":"BACKSTREET","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L10_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"이보쇼, 할배. 아까부터 사람 깔보는 투로 말하는데......","JPN":"おい、ジジイ。さっきから、人のことを小馬鹿にしやがって……","ENG":"Listen, old man. I don't appreciate the condescending tone in your voice...","TWN":"喂，老頭。從剛才開始，你就一直在用輕蔑的口吻對我說話……"},"stage":{"bg":"BACKSTREET","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L12_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"으헉!","JPN":"うわっ！","ENG":"Eek!","TWN":"呃呵！"},"stage":{"bg":"BACKSTREET","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_COMBAT_MONSTER_HIT_SMALL"},{"id":"L13_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"요약하면 이렇게 길바닥에 드러눕기 십상이란 뜻이지.","JPN":"要するに、こんな風に道端に転がることになる、ということだ。","ENG":"To put it succinctly, you're far too prone to end up on the ground like this.","TWN":"簡單來說，就是經常像這樣被打趴在地上的意思。"},"stage":{"bg":"BACKSTREET","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"이런 망할 영감탱이를 봤나! 설교 그만하고 이거 놔!","JPN":"このクソジジイが！　説教はいいから、とっとと放せ！","ENG":"You blasted old fool! Stop lecturing me and let me go!","TWN":"真是討人厭的老頭！別再說教了，放開我！"},"stage":{"bg":"BACKSTREET","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L17_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"하하. 놔 주는 대신 내가 제안을 하나 하지.","JPN":"はは。放す代わりに一つ提案をしよう。","ENG":"Hah hah. I will release you, on one condition.","TWN":"哈哈，我可以放了你啊，但我還是對你提一個提議好了。"},"stage":{"bg":"BACKSTREET","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L18_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"날 따라오면 제대로 된 카운터의 싸움법을 가르쳐 주겠네. 어떤가?","JPN":"俺について来れば、ちゃんとしたカウンターの戦い方を教えてやる。どうだ？","ENG":"Come with me, and I will show you how a true Counter fights. What do you say?","TWN":"只要你跟我走，我就教你制裁者的真正戰鬥技巧，怎麼樣？"},"stage":{"bg":"BACKSTREET","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L19_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"웃기시네! 난 관심 없어!","JPN":"ふざけんな！　俺はそんなものに興味ない！","ENG":"Bollocks! I'm not interested!","TWN":"笑死人了！沒興趣！"},"stage":{"bg":"BACKSTREET","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L20_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"엇차, 수줍음이 많은 성격이군.","JPN":"よいしょっと、照れ屋なんだな。","ENG":"Oh my. The shy type, are you?","TWN":"唉呀，沒想到你是個害羞鬼啊。"},"stage":{"bg":"BACKSTREET","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L22_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"괜찮아. 자네 아버지가 진 빚까지 해결할 기회니까.","JPN":"気にすんな。君の父さんへの借りを返すチャンスだしな。","ENG":"It's alright. This is your chance to pay off your father's debts.","TWN":"沒關係，這可是連你父親欠下的債都能一筆勾銷的好機會。"},"stage":{"bg":"BACKSTREET","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"사람 살려! 납치범이다! 납치버어어엄!!","JPN":"助けてくれ！　人さらいだ！　拉致された！","ENG":"Help! I'm being kidnapped! This is an abduction!","TWN":"救命啊！綁架啦！有綁架犯啊啊！！"},"stage":{"bg":"BACKSTREET","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}}]`);export{e as default};